class Solution:
    def maxProfit(self, prices, strategy, k):
        n = len(prices)
        base = sum(strategy[i] * prices[i] for i in range(n))
        best = base
        h = k // 2
        for j in range(0, n - k + 1):
            modified = list(strategy)
            for t in range(j, j + h):
                modified[t] = 0
            for t in range(j + h, j + k):
                modified[t] = 1
            profit = sum(modified[i] * prices[i] for i in range(n))
            if profit > best:
                best = profit
        return best

