var maxProfit = function(prices, strategy, k) {
    const n = prices.length;
    const h = k / 2;
    const prePrice = new Array(n + 1).fill(0);
    const preSp = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prePrice[i + 1] = prePrice[i] + prices[i];
        preSp[i + 1] = preSp[i] + strategy[i] * prices[i];
    }
    const base = preSp[n];
    let bestDelta = 0;
    for (let j = 0; j + k <= n; j++) {
        const orig = preSp[j + k] - preSp[j];
        const secondHalf = prePrice[j + k] - prePrice[j + h];
        const delta = secondHalf - orig;
        if (delta > bestDelta) bestDelta = delta;
    }
    return base + bestDelta;
};
